// ArrayList — fast random access
List<String> al = new ArrayList<>();
al.add("a"); al.add("b"); al.add("c");
String s = al.get(1);           // O(1)
al.add(1, "x");                 // O(n) — shifts b, c right

// LinkedList — fast head/tail ops
Deque<String> ll = new LinkedList<>();
ll.addFirst("head");            // O(1)
ll.addLast("tail");             // O(1)
String head = ll.peekFirst();   // O(1)

// LinkedList as List is rarely better than ArrayList
// Prefer LinkedList only when used as a Deque

Set<String> hash = new HashSet<>(List.of("banana", "apple", "cherry"));
// iteration order: unpredictable

Set<String> linked = new LinkedHashSet<>(List.of("banana", "apple", "cherry"));
// iteration order: banana, apple, cherry (insertion order)

Set<String> tree = new TreeSet<>(List.of("banana", "apple", "cherry"));
// iteration order: apple, banana, cherry (sorted)

// TreeSet extras
String first = tree.first();              // "apple"
String ceiling = tree.ceiling("b");       // "banana" (>= "b")
NavigableSet<String> head = tree.headSet("cherry", false); // [apple, banana]

List<String> listeners = new CopyOnWriteArrayList<>();

// Writer thread
listeners.add("listenerA"); // copies entire array

// Reader threads — never throw ConcurrentModificationException
for (String l : listeners) {
    // iterates over the snapshot taken when iterator was created
    // even if another thread adds/removes during iteration
    process(l);
}

// NOT suitable for write-heavy workloads:
// 1000 threads each calling add() = 1000 full array copies

// Initial capacity and load factor
Map<String, Integer> map = new HashMap<>(16, 0.75f);

// equals/hashCode contract MUST be consistent
// Bad: mutable key
class Bad {
    int id;
    public int hashCode() { return id; } // id can change!
}

// Good: immutable key
record Point(int x, int y) {}  // record auto-generates correct equals/hashCode
Map<Point, String> grid = new HashMap<>();
grid.put(new Point(1, 2), "A");  // safe

// Check resize threshold: 16 * 0.75 = 12 entries triggers resize
// Pre-size to avoid resize: new HashMap<>(expectedSize / 0.75 + 1)

// LRU cache using LinkedHashMap access-order mode
int capacity = 3;
Map<Integer, String> lru = new LinkedHashMap<>(capacity, 0.75f, true) {
    protected boolean removeEldestEntry(Map.Entry<Integer,String> eldest) {
        return size() > capacity;
    }
};
lru.put(1, "a"); lru.put(2, "b"); lru.put(3, "c");
lru.get(1);      // moves 1 to most-recently-used position
lru.put(4, "d"); // evicts 2 (least recently used)

// TreeMap range queries
TreeMap<Integer, String> scores = new TreeMap<>();
scores.put(50, "C"); scores.put(70, "B"); scores.put(90, "A");
Map.Entry<Integer,String> floor = scores.floorEntry(75); // 70->B
Map<Integer,String> top = scores.tailMap(70);            // {70->B, 90->A}

ConcurrentHashMap<String, Integer> counts = new ConcurrentHashMap<>();

// WRONG — get then put is NOT atomic
Integer val = counts.get("key");
counts.put("key", val == null ? 1 : val + 1); // race condition!

// CORRECT — merge is atomic
counts.merge("key", 1, Integer::sum);

// CORRECT — compute is atomic
counts.compute("key", (k, v) -> v == null ? 1 : v + 1);

// putIfAbsent — atomic, returns existing value or null
String existing = map.putIfAbsent("key", "newVal");

// size() is approximate under concurrent modification
// use mappingCount() for long result
long approxSize = counts.mappingCount();
